import{_ as a,o as s,c as e,a4 as n}from"./chunks/framework.BIesbIg_.js";const k=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"guide/benchmarks.md","filePath":"guide/benchmarks.md"}'),i={name:"guide/benchmarks.md"};function r(d,t,l,o,h,p){return s(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><p>Two independent evaluations prove GCF&#39;s superiority: a comprehension accuracy test (do LLMs understand it?) and a token efficiency test (how many tokens does it cost?).</p><h2 id="llm-comprehension-accuracy" tabindex="-1">LLM Comprehension Accuracy <a class="header-anchor" href="#llm-comprehension-accuracy" aria-label="Permalink to &quot;LLM Comprehension Accuracy&quot;">​</a></h2><p><strong>Setup:</strong> 500 symbols, 200 edges. Same payload encoded in GCF, TOON, and JSON. Six structured extraction questions sent to an LLM. Deterministic ground truth, no LLM judge.</p><table tabindex="0"><thead><tr><th>Format</th><th>Accuracy</th><th>Tokens</th><th>vs JSON</th></tr></thead><tbody><tr><td><strong>GCF</strong></td><td><strong>100%</strong> (6/6)</td><td><strong>11,090</strong></td><td><strong>79% fewer</strong></td></tr><tr><td>TOON</td><td>100% (6/6)</td><td>16,378</td><td>69% fewer</td></tr><tr><td>JSON</td><td>66.7% (4/6)</td><td>53,341</td><td>baseline</td></tr></tbody></table><h3 id="what-json-got-wrong" tabindex="-1">What JSON got wrong <a class="header-anchor" href="#what-json-got-wrong" aria-label="Permalink to &quot;What JSON got wrong&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Question</th><th>Expected</th><th>JSON answered</th></tr></thead><tbody><tr><td>&quot;How many symbols?&quot;</td><td>500</td><td>320</td></tr><tr><td>&quot;How many targets (distance 0)?&quot;</td><td>166</td><td>240</td></tr></tbody></table><p>At 500 records, JSON&#39;s field-name repetition creates enough noise that the model loses count. It&#39;s not hallucinating; it&#39;s drowning in structural tokens that carry no semantic content.</p><h3 id="what-gcf-got-right" tabindex="-1">What GCF got right <a class="header-anchor" href="#what-gcf-got-right" aria-label="Permalink to &quot;What GCF got right&quot;">​</a></h3><p>All six questions answered correctly:</p><ol><li>Symbol count: 500 ✓</li><li>Edge count: 200 ✓</li><li>Highest-scored symbol name ✓</li><li>Kind of highest-scored symbol ✓</li><li>Target count (distance 0): 166 ✓</li><li>All unique edge types (alphabetical) ✓</li></ol><p>GCF achieves this at 32% fewer tokens than TOON, which also scored 100%.</p><h3 id="reproduce" tabindex="-1">Reproduce <a class="header-anchor" href="#reproduce" aria-label="Permalink to &quot;Reproduce&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/blackwell-systems/gcf-go</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gcf-go/eval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; GOWORK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">off</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TestComprehension</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -timeout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 15m</span></span></code></pre></div><p>Eval source: <a href="https://github.com/blackwell-systems/gcf-go/tree/main/eval" target="_blank" rel="noreferrer">gcf-go/eval</a></p><hr><h2 id="token-efficiency-toon-s-own-benchmark" tabindex="-1">Token Efficiency (TOON&#39;s Own Benchmark) <a class="header-anchor" href="#token-efficiency-toon-s-own-benchmark" aria-label="Permalink to &quot;Token Efficiency (TOON&#39;s Own Benchmark)&quot;">​</a></h2><p>We inserted GCF into <a href="https://github.com/toon-format/toon/tree/main/benchmarks" target="_blank" rel="noreferrer">TOON&#39;s token efficiency benchmark</a>. Their datasets, their tokenizer (gpt-tokenizer, o200k_base), their methodology. The only change: one additional formatter.</p><h3 id="mixed-structure-track" tabindex="-1">Mixed-Structure Track <a class="header-anchor" href="#mixed-structure-track" aria-label="Permalink to &quot;Mixed-Structure Track&quot;">​</a></h3><p>Datasets with nested or semi-uniform structures. This is where most real-world data lives.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Semi-uniform event logs (2000 records):</span></span>
<span class="line"><span>  TOON   ████████████████████████████████████████████████████  154,032</span></span>
<span class="line"><span>  GCF    ████████████████████████████████████░░░░░░░░░░░░░░░  107,269  ◀ 44% smaller</span></span>
<span class="line"><span></span></span>
<span class="line"><span>E-commerce orders (500 orders, nested items):</span></span>
<span class="line"><span>  TOON   ████████████████████████████████████████████████████   73,246</span></span>
<span class="line"><span>  GCF    ████████████████████████████████████████████░░░░░░░   61,592  ◀ 19% smaller</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Mixed-structure total:</span></span>
<span class="line"><span>  TOON   ████████████████████████████████████████████████████  227,896</span></span>
<span class="line"><span>  GCF    █████████████████████████████████████░░░░░░░░░░░░░░  169,554  ◀ 34% smaller</span></span></code></pre></div><h3 id="flat-only-track" tabindex="-1">Flat-Only Track <a class="header-anchor" href="#flat-only-track" aria-label="Permalink to &quot;Flat-Only Track&quot;">​</a></h3><p>Pure tabular data. TOON&#39;s claimed sweet spot. GCF still wins.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Employee records (2000 rows):</span></span>
<span class="line"><span>  TOON   ████████████████████████████████████████████████████   49,966</span></span>
<span class="line"><span>  GCF    ██████████████████████████████████████████████████░░   49,054  ◀ 2% smaller</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Analytics time-series (365 days):</span></span>
<span class="line"><span>  TOON   ████████████████████████████████████████████████████    9,127</span></span>
<span class="line"><span>  GCF    ████████████████████████████████████████████████░░░░    8,397  ◀ 8% smaller</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Flat-only total:</span></span>
<span class="line"><span>  TOON   ████████████████████████████████████████████████████   67,837</span></span>
<span class="line"><span>  GCF    ██████████████████████████████████████████████████░░   66,026  ◀ 3% smaller</span></span></code></pre></div><h3 id="per-dataset-breakdown" tabindex="-1">Per-Dataset Breakdown <a class="header-anchor" href="#per-dataset-breakdown" aria-label="Permalink to &quot;Per-Dataset Breakdown&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Dataset</th><th>Structure</th><th>GCF</th><th>TOON</th><th>CSV</th><th>JSON</th></tr></thead><tbody><tr><td>Event logs</td><td>Semi-uniform</td><td><strong>107,269</strong></td><td>154,032</td><td>n/a</td><td>181,141</td></tr><tr><td>E-commerce</td><td>Nested</td><td><strong>61,592</strong></td><td>73,246</td><td>n/a</td><td>109,574</td></tr><tr><td>Nested config</td><td>Deep</td><td>693</td><td><strong>618</strong></td><td>n/a</td><td>905</td></tr><tr><td>Employees</td><td>Flat</td><td><strong>49,054</strong></td><td>49,966</td><td>47,137</td><td>127,050</td></tr><tr><td>Analytics</td><td>Flat</td><td><strong>8,397</strong></td><td>9,127</td><td>8,395</td><td>22,257</td></tr><tr><td>GitHub repos</td><td>Flat</td><td><strong>8,575</strong></td><td>8,744</td><td>8,512</td><td>15,144</td></tr></tbody></table><p>TOON&#39;s only win: deeply nested configuration. A 75-token difference on a 618-token payload.</p><h3 id="why-gcf-wins-on-semi-uniform-data" tabindex="-1">Why GCF wins on semi-uniform data <a class="header-anchor" href="#why-gcf-wins-on-semi-uniform-data" aria-label="Permalink to &quot;Why GCF wins on semi-uniform data&quot;">​</a></h3><p>TOON&#39;s tabular format requires all rows to have identical fields. When data is semi-uniform (event logs where 50% have nested error objects), TOON falls back to its less efficient nested encoding for the entire array.</p><p>GCF handles semi-uniformity natively: primitive fields encode positionally, nested fields attach inline only when present. No format-level &quot;mode switch&quot; is required.</p><h3 id="reproduce-1" tabindex="-1">Reproduce <a class="header-anchor" href="#reproduce-1" aria-label="Permalink to &quot;Reproduce&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/blackwell-systems/toon.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> toon</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gcf-comparison</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmark:tokens</span></span></code></pre></div><p>Fork: <a href="https://github.com/blackwell-systems/toon/tree/gcf-comparison" target="_blank" rel="noreferrer">blackwell-systems/toon@gcf-comparison</a></p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>GCF</th><th>TOON</th><th>JSON</th></tr></thead><tbody><tr><td>Comprehension accuracy (500 sym)</td><td>100%</td><td>100%</td><td>66.7%</td></tr><tr><td>Tokens (500 symbols)</td><td>11,090</td><td>16,378</td><td>53,341</td></tr><tr><td>vs JSON savings</td><td>79%</td><td>69%</td><td>baseline</td></tr><tr><td>vs TOON savings</td><td>32%</td><td>baseline</td><td>n/a</td></tr><tr><td>Mixed-structure efficiency</td><td>best</td><td>34% larger</td><td>72% larger</td></tr><tr><td>Flat-data efficiency</td><td>best</td><td>3% larger</td><td>149% larger</td></tr><tr><td>Session dedup (5th call)</td><td>92.7%</td><td>unavailable</td><td>unavailable</td></tr><tr><td>Delta encoding</td><td>81.2%</td><td>unavailable</td><td>unavailable</td></tr></tbody></table><p>GCF wins on token efficiency, matches on comprehension accuracy, and offers session/delta features no competitor has.</p>`,37)])])}const g=a(i,[["render",r]]);export{k as __pageData,g as default};
